INSERT INTO catalog_foods (id, name, name_en, category, image, texture, fatty, umami, acidity, sweetness, wateriness, aroma, best_for, advantage, disadvantage, vibe_note) VALUES
('salmon', '三文鱼', 'Salmon', '海鲜蛋白', 'https://img.icons8.com/stickers/200/000000/salmon-sushi.png', '丝滑', 9, 8, 2, 1, 4, 6, '寿司碗、轻食沙拉、拌饭和吐司', '口感高级、油脂饱满、鲜味稳定', '价格高、保鲜要求高', '适合提供顺滑油脂感和明显鲜味，是冷食里非常强势的主角食材。'),
('avocado', '牛油果', 'Avocado', '果脂类', 'https://img.icons8.com/stickers/200/000000/avocado.png', '绵密', 9, 6, 1, 1, 5, 4, '寿司碗、开放三明治、沙拉和酱泥', '容易买到，能补足丝滑感和油脂感', '海鲜鲜味弱，整体更偏植物清香', '很适合承担丝滑和丰润感，但无法完整复刻海产的咸鲜气质。'),
('egg', '鸡蛋', 'Egg', '日常蛋白', 'https://img.icons8.com/stickers/200/000000/egg.png', '软嫩', 5, 6, 1, 1, 5, 4, '早餐碗、三明治、盖饭和简易沙拉', '便宜、常见、烹饪门槛低', '风味更温和，视觉冲击力不如生鲜蛋白', '鸡蛋在居家替代里非常实用，能提供柔软口感和一定鲜味，但风格更家常。'),
('tofu', '豆腐', 'Tofu', '植物蛋白', 'https://img.icons8.com/stickers/200/000000/tofu.png', '软嫩', 2, 5, 1, 1, 7, 2, '拌饭、味噌汤、清淡炒菜和轻食碗', '低脂、健康、价格友好，适合大多数家庭常备', '油脂感不足，需要额外调味或酱汁辅助', '豆腐很擅长接住清淡和软嫩的部分，但不适合直接替代高油脂食材的满足感。'),
('milk', '牛奶', 'Milk', '乳制品', 'https://img.icons8.com/stickers/200/000000/milk-bottle.png', '顺滑', 6, 3, 3, 3, 8, 3, '拿铁、燕麦杯、奶油汤和基础烘焙', '适配范围广，是许多饮品和甜品的基础液体', '乳糖不耐受人群不友好', '牛奶偏中性、顺滑，适合作为液体基底。很多替代品都是在模仿它的顺口和乳感。'),
('yogurt', '酸奶', 'Yogurt', '乳制品', 'https://img.icons8.com/stickers/200/000000/yogurt.png', '浓稠', 5, 2, 8, 3, 5, 4, '冷饮、酱汁、隔夜燕麦和轻甜点', '浓稠度强，发酵感能让风味更立体', '酸度高，不适合所有咖啡和甜点场景', '酸奶比牛奶更有个性，适合替代质地，但会明显改变风味走向。'),
('chicken-breast', '鸡胸肉', 'Chicken Breast', '家常蛋白', 'https://img.icons8.com/stickers/200/000000/chicken-breast.png', '紧实', 2, 7, 1, 1, 4, 4, '健身沙拉、热碗饭、卷饼和三明治', '高蛋白、低脂、好获取', '如果处理不好容易偏柴，顺滑感不强', '鸡胸肉胜在实用和稳定，更像是功能型替代，而不是气质完全复刻。'),
('beef', '牛肉', 'Beef', '红肉蛋白', 'https://img.icons8.com/stickers/200/000000/steak.png', '紧实', 6, 9, 1, 1, 3, 7, '能量碗、热拌饭、意面和煎炒主菜', '鲜味很强，饱腹感和存在感都足', '价格偏高，整体调性更厚重', '牛肉在鲜味维度很强，适合作为强风味替代，但会把菜整体拉向更浓郁的方向。'),
('tuna', '金枪鱼', 'Tuna', '海鲜蛋白', 'https://placehold.co/200x200/F6EFE3/243127?text=Tuna', '紧实', 4, 8, 1, 1, 4, 6, '寿司碗、三明治夹馅、沙拉和蛋白碗', '鲜味强、蛋白高，很多冷食里都好替换', '油脂感不如三文鱼，口感更紧实', '金枪鱼更偏干净和利落，适合替代海鲜主角位，但整体风格更清爽。'),
('shrimp', '虾仁', 'Shrimp', '海鲜蛋白', 'https://placehold.co/200x200/F6EFE3/243127?text=Shrimp', '弹嫩', 2, 7, 1, 2, 5, 5, '轻食碗、意面、炒饭和快手沙拉', '熟制快、鲜味稳定、存在感明显', '油脂感弱，冷食时不够丝滑', '虾仁像一个更轻盈的海鲜替身，适合保住鲜味但不适合复刻油润感。'),
('pork', '猪肉', 'Pork', '家常蛋白', 'https://placehold.co/200x200/F6EFE3/243127?text=Pork', '紧实', 5, 7, 1, 1, 4, 5, '家常炒菜、盖饭、三明治和热食碗', '家用普适性高，兼顾鲜味和油脂', '风格偏厚重，不适合所有清爽场景', '猪肉比鸡胸更圆润，适合补足一点脂香，但整体气质会更家常。'),
('tempeh', '天贝', 'Tempeh', '植物蛋白', 'https://placehold.co/200x200/F6EFE3/243127?text=Tempeh', '紧实', 4, 6, 1, 1, 3, 5, '植物蛋白碗、卷饼、沙拉和热三明治', '蛋白密度高，咬感更接近肉类', '豆发酵风味明显，不一定适合所有人', '天贝比豆腐更像肉类替代，特别适合需要紧实口感的场景。'),
('chickpeas', '鹰嘴豆', 'Chickpeas', '植物蛋白', 'https://placehold.co/200x200/F6EFE3/243127?text=Chickpeas', '绵实', 2, 4, 1, 2, 3, 3, '沙拉、豆泥酱、烤碗和植物蛋白拼盘', '便于储存，饱腹感强，适合做豆泥和烤豆', '鲜味和油脂感都偏弱，需要调味支持', '鹰嘴豆更像是温和稳妥的结构型替代，适合撑起体积和绵密感。'),
('oat-milk', '燕麦奶', 'Oat Milk', '植物奶', 'https://placehold.co/200x200/F6EFE3/243127?text=Oat+Milk', '顺滑', 4, 1, 2, 4, 8, 3, '拿铁、谷物碗、奶昔和轻烘焙', '植物感柔和，和咖啡搭配接受度高', '乳感和鲜味不如牛奶，容易略甜', '燕麦奶是很实用的牛奶替代，核心优势是顺滑度和易搭配性。'),
('coconut-milk', '椰奶', 'Coconut Milk', '植物奶', 'https://placehold.co/200x200/F6EFE3/243127?text=Coconut+Milk', '浓滑', 8, 2, 1, 3, 6, 6, '咖喱、热带风味甜品、奶昔和浓汤', '油脂感足，能快速补出奶香和厚度', '椰香明显，会强烈改变风味方向', '椰奶擅长补足浓润感，但会把菜整体拉向热带和甜香方向。'),
('cream', '淡奶油', 'Cream', '乳制品', 'https://placehold.co/200x200/F6EFE3/243127?text=Cream', '浓滑', 9, 2, 2, 2, 4, 3, '意面酱、奶油汤、蛋糕和甜品夹层', '厚度和顺滑度很强，能快速建立浓郁口感', '热量高，日常替代成本偏重', '淡奶油像是把乳感推到更厚重的一端，适合做口感加强型替代。'),
('butter', '黄油', 'Butter', '乳制品', 'https://placehold.co/200x200/F6EFE3/243127?text=Butter', '油润', 10, 2, 1, 1, 1, 5, '烘焙、煎香、做酱和抹面提香', '脂香强，少量就能显著提升满足感', '液体替代能力差，风格很重', '黄油更像是油脂和香气补强器，不是所有奶类都能直接用它顶。'),
('mozzarella', '马苏里拉', 'Mozzarella', '乳制品', 'https://placehold.co/200x200/F6EFE3/243127?text=Mozzarella', '拉丝', 7, 5, 2, 1, 4, 4, '披萨、烤吐司、焗饭和卡普雷塞沙拉', '拉丝表现强，视觉效果好', '风味比较温和，不是浓郁型奶酪', '马苏里拉更像结构和拉丝担当，适合视觉和口感迁移。'),
('cream-cheese', '奶油奶酪', 'Cream Cheese', '乳制品', 'https://placehold.co/200x200/F6EFE3/243127?text=Cream+Cheese', '厚滑', 8, 3, 3, 2, 3, 4, '贝果、芝士蛋糕、奶酪酱和夹馅', '质地稳定，抹面和夹层表现很好', '风格偏厚，不适合替代轻盈乳品', '奶油奶酪是更厚、更稳的乳感版本，适合需要稠度和附着力的场景。'),
('mushroom', '蘑菇', 'Mushroom', '鲜蔬菌菇', 'https://placehold.co/200x200/F6EFE3/243127?text=Mushroom', '柔嫩', 1, 8, 1, 1, 5, 6, '意面、炖饭、汉堡和植物系主菜', '鲜味很强，是很多肉类替代里的核心角色', '缺少真正的油脂感，口感也更轻', '蘑菇是鲜味迁移的明星选手，特别适合补足肉类缺位时的气场。'),
('tomato', '番茄', 'Tomato', '鲜蔬果', 'https://placehold.co/200x200/F6EFE3/243127?text=Tomato', '多汁', 1, 4, 7, 3, 9, 4, '意面酱、沙拉、炖菜和烤盘料理', '酸甜平衡好，含水量高，适合带出清爽感', '本体感偏轻，不适合顶替厚重食材', '番茄擅长补酸度和汁感，是很多料理里风味平衡器而不是主体油脂源。'),
('cucumber', '黄瓜', 'Cucumber', '鲜蔬果', 'https://placehold.co/200x200/F6EFE3/243127?text=Cucumber', '脆爽', 0, 1, 1, 1, 10, 2, '三明治、卷饼、冷盘和清爽沙拉', '清爽、便宜、含水量高，适合补脆感', '风味和厚度都弱，不能承担主角食材功能', '黄瓜更像质地和清爽度替代，不适合承担浓郁型食材的角色。'),
('cauliflower', '花椰菜', 'Cauliflower', '鲜蔬果', 'https://placehold.co/200x200/F6EFE3/243127?text=Cauliflower', '松散', 0, 3, 1, 2, 4, 2, '低碳米饭替代、烤盘菜和浓汤', '吸味能力好，适合做结构型主食替代', '自身风味轻，饱腹感和主食感有限', '花椰菜常用来顶主食或做绵松底层，更像结构迁移而不是风味迁移。'),
('spinach', '菠菜', 'Spinach', '鲜蔬果', 'https://placehold.co/200x200/F6EFE3/243127?text=Spinach', '柔软', 0, 3, 1, 1, 7, 3, '蛋饼、意面、轻汤和早餐碗', '颜色和柔软叶感都适合补绿色蔬菜位', '体积塌缩明显，存在感偏弱', '菠菜偏柔和，适合用来接住绿叶菜角色，但不适合做质地主角。'),
('zucchini', '西葫芦', 'Zucchini', '鲜蔬果', 'https://placehold.co/200x200/F6EFE3/243127?text=Zucchini', '柔嫩', 0, 2, 1, 2, 8, 2, '烤盘菜、意面、轻煎配菜和低碳料理', '容易吸味，熟后质地柔软', '本身风味弱，容易出水', '西葫芦适合承担轻盈蔬菜位，能补柔软感但不适合浓味主菜替代。'),
('potato', '土豆', 'Potato', '根茎主食', 'https://placehold.co/200x200/F6EFE3/243127?text=Potato', '绵密', 0, 2, 1, 1, 3, 2, '泥、薯块、浓汤和焗烤配菜', '饱腹感强，绵密度高，适合补体积', '风味比较平，不提供鲜味和油脂', '土豆是非常强的结构型替代，擅长给菜增加厚实感和绵密感。'),
('banana', '香蕉', 'Banana', '鲜蔬果', 'https://placehold.co/200x200/F6EFE3/243127?text=Banana', '绵密', 1, 1, 2, 8, 5, 6, '奶昔、燕麦碗、松饼和健康烘焙', '天然甜度高，能补黏合感和绵密口感', '香蕉香气明显，不适合所有甜品替代', '香蕉在甜口替代里很强，尤其适合接住绵密感和天然甜味。'),
('rice', '米饭', 'Rice', '主食谷物', 'https://placehold.co/200x200/F6EFE3/243127?text=Rice', '软弹', 0, 1, 0, 1, 4, 1, '饭碗、咖喱饭、炒饭和寿司饭底', '中性稳定，是最通用的主食底座之一', '本身风味弱，需要靠配料和酱汁撑气质', '米饭像一个中性底板，自己不抢戏，但能托住很多替代组合。'),
('pasta', '意面', 'Pasta', '主食谷物', 'https://placehold.co/200x200/F6EFE3/243127?text=Pasta', '弹韧', 1, 1, 0, 1, 3, 1, '奶油面、番茄面、焗面和冷面沙拉', '酱汁承载能力强，口感稳定', '风味中性，无法替代米饭那种颗粒分明感', '意面更重视弹韧和挂汁能力，适合作为酱汁型主食底。'),
('bread', '面包', 'Bread', '主食谷物', 'https://placehold.co/200x200/F6EFE3/243127?text=Bread', '蓬松', 2, 2, 1, 2, 2, 4, '三明治、吐司盘、开放面包和法式早餐', '上手快，适合承载酱料和主料', '含水量低，不适合替代湿润型主食', '面包更像一个蓬松载体，擅长接住夹馅和抹酱场景。'),
('oats', '燕麦', 'Oats', '主食谷物', 'https://placehold.co/200x200/F6EFE3/243127?text=Oats', '糊化', 3, 1, 1, 2, 4, 3, '早餐碗、隔夜燕麦、能量棒和健康烘焙', '饱腹感好，和奶类与水果兼容性高', '颗粒感和面粉结构不能完全互替', '燕麦偏温和和健康路线，适合早餐和轻烘焙里的基础替代。'),
('flour', '面粉', 'Flour', '烘焙原料', 'https://placehold.co/200x200/F6EFE3/243127?text=Flour', '粉质', 1, 1, 0, 1, 0, 1, '蛋糕、饼干、面糊和基础面团', '用途广，是烘焙和勾芡的基础骨架', '结构性强，但风味信息很少', '面粉不是风味型材料，更像是结构框架，很多替代都在和它的成型能力竞争。'),
('soy-sauce', '酱油', 'Soy Sauce', '酱料调味', 'https://placehold.co/200x200/F6EFE3/243127?text=Soy+Sauce', '液体', 0, 9, 1, 1, 9, 5, '日式饭碗、蘸汁、炒菜和酱汁打底', '鲜味强，少量就能显著补味', '咸度高，不提供油脂和厚度', '酱油是鲜味和咸香的捷径，适合补风味，不适合补质地。'),
('miso', '味噌', 'Miso', '酱料调味', 'https://placehold.co/200x200/F6EFE3/243127?text=Miso', '厚糊', 2, 9, 2, 2, 3, 6, '味噌汤、酱烤、蘸酱和咸口调味底', '发酵鲜味强，稠度比酱油更能挂味', '风格明显，不适合所有西式场景', '味噌是更厚、更发酵感的鲜味来源，适合做咸口风味加强型替代。'),
('mayonnaise', '蛋黄酱', 'Mayonnaise', '酱料调味', 'https://placehold.co/200x200/F6EFE3/243127?text=Mayo', '浓滑', 9, 3, 6, 2, 2, 3, '三明治、沙拉、蘸酱和日式小食', '既补油脂又补酸感，做冷食很高效', '风味方向固定，热应用场景有限', '蛋黄酱是冷食里很强的质地修复器，尤其适合补浓滑和酸感。'),
('olive-oil', '橄榄油', 'Olive Oil', '酱料调味', 'https://placehold.co/200x200/F6EFE3/243127?text=Olive+Oil', '油润', 10, 0, 1, 0, 0, 4, '沙拉、烤菜、意面和蘸面包', '补油脂效率高，适合把轻食拉得更润', '单独使用时风味层次有限', '橄榄油更像油脂度补偿工具，适合给原本偏干的替代品加回顺滑感。'),
('peanut-butter', '花生酱', 'Peanut Butter', '酱料调味', 'https://placehold.co/200x200/F6EFE3/243127?text=Peanut+Butter', '厚糊', 9, 2, 1, 3, 1, 7, '吐司、能量杯、东南亚风味酱汁和曲奇', '香气和厚度都强，少量即可显著提升满足感', '花生风味太明显，不适合中性替代', '花生酱擅长做高存在感替代，特别适合厚重、香气型场景。'),
('salmon-x1', '三文鱼扩展款1', 'Salmon Variant 1', '海鲜蛋白', 'https://img.icons8.com/stickers/200/000000/salmon-sushi.png', '紧实', 8, 9, 2, 1, 5, 6, '寿司碗、轻食沙拉、拌饭和吐司（扩展款1）', '口感高级、油脂饱满、鲜味稳定，更适合做结构替代测试。', '价格高、保鲜要求高，风味表现会有轻微偏移。', '适合提供顺滑油脂感和明显鲜味，是冷食里非常强势的主角食材。 该版本用于扩展样本库，保持核心定位并加入小幅结构变化。'),
('avocado-x2', '牛油果扩展款2', 'Avocado Variant 2', '果脂类', 'https://img.icons8.com/stickers/200/000000/avocado.png', '弹嫩', 9, 5, 2, 1, 4, 5, '寿司碗、开放三明治、沙拉和酱泥（扩展款2）', '容易买到，能补足丝滑感和油脂感，更适合做结构替代测试。', '海鲜鲜味弱，整体更偏植物清香，风味表现会有轻微偏移。', '很适合承担丝滑和丰润感，但无法完整复刻海产的咸鲜气质。 该版本用于扩展样本库，保持核心定位并加入小幅结构变化。'),
('egg-x3', '鸡蛋扩展款3', 'Egg Variant 3', '日常蛋白', 'https://img.icons8.com/stickers/200/000000/egg.png', '柔嫩', 6, 6, 0, 2, 5, 3, '早餐碗、三明治、盖饭和简易沙拉（扩展款3）', '便宜、常见、烹饪门槛低，更适合做结构替代测试。', '风味更温和，视觉冲击力不如生鲜蛋白，风味表现会有轻微偏移。', '鸡蛋在居家替代里非常实用，能提供柔软口感和一定鲜味，但风格更家常。 该版本用于扩展样本库，保持核心定位并加入小幅结构变化。'),
